import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Users, AlertTriangle, Receipt, CheckCircle, TrendingUp, QrCode, MapPin } from 'lucide-react';
import { useAuth } from '../context/AuthContext';

const Dashboard = () => {
  const { user } = useAuth();
  const [stats, setStats] = useState({
    totalVendors: 0,
    approvedVendors: 0,
    pendingVendors: 0,
    totalViolations: 0,
    totalChallans: 0,
    revenue: 0,
    myPendingChallans: 0,
    myTotalFines: 0
  });

  useEffect(() => {
    const fetchStats = async () => {
      try {
        if (user?.role === 'ADMIN' || user?.role === 'OFFICER') {
          const [vendors, violations, challans] = await Promise.all([
            axios.get('http://localhost:8080/api/vendors'),
            axios.get('http://localhost:8080/api/violations'),
            axios.get('http://localhost:8080/api/challans')
          ]);

          const vData = vendors.data;
          const paidChallans = challans.data.filter(c => c.status === 'PAID');

          setStats({
            totalVendors: vData.length,
            approvedVendors: vData.filter(v => v.status === 'APPROVED').length,
            pendingVendors: vData.filter(v => v.status === 'PENDING').length,
            totalViolations: violations.data.length,
            totalChallans: challans.data.length,
            revenue: paidChallans.reduce((acc, c) => acc + c.fineAmount, 0)
          });
        } else if (user?.role === 'VENDOR') {
          const [challansRes] = await Promise.all([
            axios.get('http://localhost:8080/api/challans/my')
          ]);
          const myChallans = challansRes.data;
          setStats(prev => ({
            ...prev,
            myPendingChallans: myChallans.filter(c => c.status === 'UNPAID').length,
            myTotalFines: myChallans.reduce((acc, c) => acc + c.fineAmount, 0)
          }));
        }
      } catch (err) {
        console.error('Error fetching dashboard stats', err);
      }
    };
    fetchStats();
  }, [user]);

  const StatCard = ({ title, value, icon: Icon, color, subValue }) => (
    <div className="bg-white p-6 rounded-xl shadow-md border-l-4 border-l-smc-blue">
      <div className="flex justify-between items-start">
        <div>
          <p className="text-gray-500 text-sm font-medium">{title}</p>
          <h3 className="text-3xl font-bold mt-1">{value}</h3>
          {subValue && <p className="text-xs text-gray-400 mt-1">{subValue}</p>}
        </div>
        <div className={`p-3 rounded-lg ${color} text-white`}>
          <Icon size={24} />
        </div>
      </div>
    </div>
  );

  if (user?.role === 'VENDOR') {
    return (
      <div className="space-y-8">
        <div className="flex justify-between items-end">
          <div>
            <h1 className="text-3xl font-bold text-gray-800">Vendor Dashboard</h1>
            <p className="text-gray-500">Welcome back, {user.fullName}</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <StatCard 
            title="Pending Challans" 
            value={stats.myPendingChallans} 
            icon={AlertTriangle} 
            color="bg-red-500" 
            subValue="Immediate action required"
          />
          <StatCard 
            title="Total Fines" 
            value={`₹${stats.myTotalFines}`} 
            icon={Receipt} 
            color="bg-blue-600" 
          />
          <StatCard 
            title="Account Status" 
            value="ACTIVE" 
            icon={CheckCircle} 
            color="bg-green-600" 
          />
        </div>

        <div className="bg-white p-8 rounded-xl shadow-md flex flex-col md:flex-row items-center gap-8 border border-blue-100">
          <div className="bg-gray-100 p-4 rounded-xl border-2 border-dashed border-gray-300">
            <QrCode size={200} className="text-gray-400" />
            <p className="text-center text-xs text-gray-500 mt-2 font-bold uppercase">Your Vending QR</p>
          </div>
          <div className="flex-1 space-y-4">
            <h2 className="text-2xl font-bold text-gray-800">Digital ID Card</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="flex items-center gap-2 text-gray-600">
                <Users size={18} className="text-smc-blue" />
                <span className="text-sm font-medium">{user.fullName}</span>
              </div>
              <div className="flex items-center gap-2 text-gray-600">
                <MapPin size={18} className="text-smc-blue" />
                <span className="text-sm font-medium">Assigned Spot: Solapur MC</span>
              </div>
            </div>
